auto
overlap_kernel_2_0(const OverlapBlockData& bra, const int bra_begin, const int bra_end,
                          const OverlapBlockData& ket, double* spherical) -> void
{
    const double fpi = mathconst::pi_value();
    const std::size_t cdim =
        static_cast<std::size_t>(bra_end - bra_begin) * static_cast<std::size_t>(ket.ncgtos);
    const auto stride = ((cdim + 7) / 8) * 8;
    constexpr std::size_t tile = 512;

    if (g_kernel_scratch.size() < 15 * tile) g_kernel_scratch.resize(15 * tile);
    auto* s = g_kernel_scratch.data();

    double acx[tile];
    double acy[tile];
    double acz[tile];

    // the bra contracted GTOs on the outside; the ket contracted GTOs
    // tiled on the inside, the tile the SIMD axis
    for (int i = bra_begin; i < bra_end; i++)
    {
        const double bx = bra.x[i];
        const double by = bra.y[i];
        const double bz = bra.z[i];
        const std::size_t ij_base = static_cast<std::size_t>(i - bra_begin) * static_cast<std::size_t>(ket.ncgtos);

        for (int j0 = 0; j0 < ket.ncgtos; j0 += static_cast<int>(tile))
        {
            const std::size_t w =
                (j0 + static_cast<int>(tile) < ket.ncgtos) ? tile : static_cast<std::size_t>(ket.ncgtos - j0);

            // AC = A − C, per ket contracted GTO of the tile
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
            {
                acx[jj] = bx - ket.x[j0 + jj];
                acy[jj] = by - ket.y[j0 + jj];
                acz[jj] = bz - ket.z[j0 + jj];
            }

            // (1) the contracted seed ladder [0]^m
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++) s[0 + jj] = 0.0;
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++) s[512 + jj] = 0.0;
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++) s[1024 + jj] = 0.0;
            for (int kb = 0; kb < bra.nprims; kb++)
            {
                const double a  = bra.exponents[static_cast<std::size_t>(kb) * bra.ncgtos + i];
                const double bn = bra.norms[static_cast<std::size_t>(kb) * bra.ncgtos + i];
                const double ia = 0.5 / a;
                for (int lk = 0; lk < ket.nprims; lk++)
                {
                    const double* ke = ket.exponents + static_cast<std::size_t>(lk) * ket.ncgtos + j0;
                    const double* kn = ket.norms + static_cast<std::size_t>(lk) * ket.ncgtos + j0;
#pragma omp simd
                    for (std::size_t jj = 0; jj < w; jj++)
                    {
                        const double g    = ke[jj];
                        const double ig   = -0.5 / g;
                        const double fe   = 1.0 / (a + g);
                        const double fz   = a * g * fe;
                        const double fact = fpi * fe;
                        const double r2   = acx[jj] * acx[jj] + acy[jj] * acy[jj] + acz[jj] * acz[jj];
                        const double wgt  = bn * kn[jj] * fact * std::sqrt(fact) * std::exp(-fz * r2);
                        double t = wgt * ia * ia;
                        s[0 + jj] += t;
                        const double f = -2.0 * a * g / (a + g);
                        t *= f;
                        s[512 + jj] += t;
                        t *= f;
                        s[1024 + jj] += t;
                    }
                }
            }

            // (2) the single-centre MD recursion [r]^0
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[1536 + jj] = acx[jj] * s[512 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[2048 + jj] = acx[jj] * s[1024 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[2560 + jj] = acy[jj] * s[512 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[3072 + jj] = acy[jj] * s[1024 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[3584 + jj] = acz[jj] * s[512 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[4096 + jj] = acz[jj] * s[1024 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[4608 + jj] = acx[jj] * s[2048 + jj] + 1.0 * s[512 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[5120 + jj] = acx[jj] * s[3072 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[5632 + jj] = acx[jj] * s[4096 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[6144 + jj] = acy[jj] * s[3072 + jj] + 1.0 * s[512 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[6656 + jj] = acy[jj] * s[4096 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[7168 + jj] = acz[jj] * s[4096 + jj] + 1.0 * s[512 + jj];

            // (3) the Cartesian-to-spherical assembly
            {
                double* out = spherical + 0 * stride + ij_base + static_cast<std::size_t>(j0);
#pragma omp simd
                for (std::size_t jj = 0; jj < w; jj++) out[jj] = 1.7320508075688772 * s[5120 + jj];
            }
            {
                double* out = spherical + 1 * stride + ij_base + static_cast<std::size_t>(j0);
#pragma omp simd
                for (std::size_t jj = 0; jj < w; jj++) out[jj] = 1.7320508075688772 * s[6656 + jj];
            }
            {
                double* out = spherical + 2 * stride + ij_base + static_cast<std::size_t>(j0);
#pragma omp simd
                for (std::size_t jj = 0; jj < w; jj++) out[jj] = -0.5 * s[4608 + jj] + -0.5 * s[6144 + jj] + 1.0 * s[7168 + jj];
            }
            {
                double* out = spherical + 3 * stride + ij_base + static_cast<std::size_t>(j0);
#pragma omp simd
                for (std::size_t jj = 0; jj < w; jj++) out[jj] = 1.7320508075688772 * s[5632 + jj];
            }
            {
                double* out = spherical + 4 * stride + ij_base + static_cast<std::size_t>(j0);
#pragma omp simd
                for (std::size_t jj = 0; jj < w; jj++) out[jj] = 0.8660254037844386 * s[4608 + jj] + -0.8660254037844386 * s[6144 + jj];
            }
        }
    }
}

