#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[29696 + jj] = acx[jj] * s[21504 + jj] + 1.0 * s[13824 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[30208 + jj] = acx[jj] * s[22528 + jj] + 1.0 * s[15360 + jj];
#pragma omp simd
            for (std::size_t jj = 0; jj < w; jj++)
                s[30720 + jj] = acx[jj] * s[23552 + jj] + 1.0 * s[16896 + jj];
#pragma omp simd
